public static function newFromStyle( $style, \DPL\Parameters $parameters, \Parser $parser ) {
	$style = strtolower( $style );
	switch ( $style ) {
		case 'category':
			$class = 'CategoryList';
			break;
		case 'definition':
			$class = 'DefinitionList';
			break;
		case 'gallery':
			$class = 'GalleryList';
			break;
		case 'inline':
			$class = 'InlineList';
			break;
		case 'ordered':
			$class = 'OrderedList';
			break;
		case 'subpage':
			$class = 'SubPageList';
			break;
		default:
		case 'unordered':
			$class = 'UnorderedList';
			break;
		case 'userformat':
			$class = 'UserFormatList';
			break;
	}
	$class = '\DPL\Lister\\' . $class;

	return new $class( $parameters, $parser );
}

