	if ( $sortColumn < 0 ) {
		switch ( $sortMethod ) {
			case 'natural':
				// Reverse natsort()
				uasort( $rowsKey, static function ( $first, $second ) {
					return strnatcmp( $second, $first );
				} );
				break;
			case 'standard':
